import scala.xml._
import scala.util.{Try, Success, Failure}
import java.io.StringReader
import javax.xml.parsers.SAXParserFactory
import org.xml.sax.InputSource

case class ConfigurationSetting(key: String, value: String, category: Option[String] = None)

case class ParsedConfiguration(
  settings: Map[String, String],
  categorizedSettings: Map[String, Map[String, String]],
  metadata: Map[String, String]
)

class ConfigurationParserService {

  def parseConfiguration(xmlString: String): Try[ParsedConfiguration] = {
    Try {
      val factory = SAXParserFactory.newInstance()
      factory.setFeature("http://xml.org/sax/features/external-general-entities", false)
      factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false)
      factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true)
      factory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false)
      factory.setXIncludeAware(false)
      factory.setNamespaceAware(true)
      
      val parser = factory.newSAXParser()
      val adapter = new scala.xml.parsing.NoBindingFactoryAdapter
      val source = new InputSource(new StringReader(xmlString))
      
      adapter.loadXML(source, parser)
    }.flatMap { elem =>
      extractConfiguration(elem)
    }
  }

  def parseConfigurationLegacy(xmlString: String): Try[ParsedConfiguration] = {
    Try {
      XML.loadString(xmlString)
    }.flatMap { elem =>
      extractConfiguration(elem)
    }
  }

  private def extractConfiguration(root: Elem): Try[ParsedConfiguration] = {
    Try {
      val settings = scala.collection.mutable.Map[String, String]()
      val categorizedSettings = scala.collection.mutable.Map[String, scala.collection.mutable.Map[String, String]]()
      val metadata = scala.collection.mutable.Map[String, String]()

      (root \ "metadata" \ "_").foreach { metaNode =>
        val key = metaNode.label
        val value = metaNode.text.trim
        if (value.nonEmpty) {
          metadata(key) = value
        }
      }

      (root \ "setting").foreach { settingNode =>
        val key = (settingNode \ "@key").text
        val value = settingNode.text.trim
        val category = (settingNode \ "@category").text
        
        if (key.nonEmpty) {
          settings(key) = value
          
          if (category.nonEmpty) {
            val catMap = categorizedSettings.getOrElseUpdate(category, scala.collection.mutable.Map[String, String]())
            catMap(key) = value
          }
        }
      }

      (root \ "settings").foreach { settingsGroup =>
        val category = (settingsGroup \ "@category").text
        
        (settingsGroup \ "setting").foreach { settingNode =>
          val key = (settingNode \ "@key").text
          val value = settingNode.text.trim
          
          if (key.nonEmpty) {
            settings(key) = value
            
            if (category.nonEmpty) {
              val catMap = categorizedSettings.getOrElseUpdate(category, scala.collection.mutable.Map[String, String]())
              catMap(key) = value
            }
          }
        }
      }

      (root \ "property").foreach { propNode =>
        val name = (propNode \ "@name").text
        val value = (propNode \ "@value").text match {
          case "" => propNode.text.trim
          case v => v
        }
        
        if (name.nonEmpty) {
          settings(name) = value
        }
      }

      ParsedConfiguration(
        settings.toMap,
        categorizedSettings.view.mapValues(_.toMap).toMap,
        metadata.toMap
      )
    }
  }

  def parseConfigurationWithEntityExpansion(xmlString: String, maxEntityExpansionSize: Int = 1000000): Try[ParsedConfiguration] = {
    if (xmlString.length > maxEntityExpansionSize) {
      return Failure(new IllegalArgumentException(s"XML size exceeds maximum allowed size: $maxEntityExpansionSize"))
    }

    Try {
      val factory = SAXParserFactory.newInstance()
      factory.setFeature("http://xml.org/sax/features/external-general-entities", false)
      factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false)
      factory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false)
      factory.setXIncludeAware(false)
      factory.setNamespaceAware(true)
      
      val parser = factory.newSAXParser()
      val adapter = new scala.xml.parsing.NoBindingFactoryAdapter
      val source = new InputSource(new StringReader(xmlString))
      
      adapter.loadXML(source, parser)
    }.flatMap { elem =>
      extractConfiguration(elem)
    }
  }

  def getSetting(config: ParsedConfiguration, key: String): Option[String] = {
    config.settings.get(key)
  }

  def getSettingsByCategory(config: ParsedConfiguration, category: String): Map[String, String] = {
    config.categorizedSettings.getOrElse(category, Map.empty)
  }

  def getAllCategories(config: ParsedConfiguration): Set[String] = {
    config.categorizedSettings.keySet
  }

  def getMetadata(config: ParsedConfiguration, key: String): Option[String] = {
    config.metadata.get(key)
  }

  def mergeConfigurations(configs: List[ParsedConfiguration]): ParsedConfiguration = {
    val mergedSettings = configs.flatMap(_.settings).toMap
    val mergedMetadata = configs.flatMap(_.metadata).toMap
    
    val mergedCategorized = configs
      .flatMap(_.categorizedSettings.toSeq)
      .groupBy(_._1)
      .view
      .mapValues(_.flatMap(_._2).toMap)
      .toMap
    
    ParsedConfiguration(mergedSettings, mergedCategorized, mergedMetadata)
  }

  def validateConfiguration(xmlString: String): Try[Boolean] = {
    parseConfiguration(xmlString).map(_ => true)
  }
}

class ConfigurationApiService(parser: ConfigurationParserService) {

  def handleConfigurationRequest(xmlPayload: String): Either[String, ParsedConfiguration] = {
    parser.parseConfiguration(xmlPayload) match {
      case Success(config) => Right(config)
      case Failure(exception) => Left(s"Failed to parse configuration: ${exception.getMessage}")
    }
  }

  def extractSetting(xmlPayload: String, key: String): Either[String, String] = {
    handleConfigurationRequest(xmlPayload) match {
      case Right(config) =>
        parser.getSetting(config, key) match {
          case Some(value) => Right(value)
          case None => Left(s"Setting not found: $key")
        }
      case Left(error) => Left(error)
    }
  }

  def extractSettingsByCategory(xmlPayload: String, category: String): Either[String, Map[String, String]] = {
    handleConfigurationRequest(xmlPayload) match {
      case Right(config) => Right(parser.getSettingsByCategory(config, category))
      case Left(error) => Left(error)
    }
  }

  def processConfigurationBatch(xmlPayloads: List[String]): List[Either[String, ParsedConfiguration]] = {
    xmlPayloads.map(handleConfigurationRequest)
  }

  def mergeConfigurationRequests(xmlPayloads: List[String]): Either[String, ParsedConfiguration] = {
    val results = processConfigurationBatch(xmlPayloads)
    val errors = results.collect { case Left(error) => error }
    
    if (errors.nonEmpty) {
      Left(s"Failed to parse some configurations: ${errors.mkString(", ")}")
    } else {
      val configs = results.collect { case Right(config) => config }
      Right(parser.mergeConfigurations(configs))
    }
  }
}

object ConfigurationManagementSystem {
  def createService(): ConfigurationApiService = {
    val parser = new ConfigurationParserService()
    new ConfigurationApiService(parser)
  }
  
  def main(args: Array[String]): Unit = {
    val service = createService()
    
    val sampleXml = """<?xml version="1.0" encoding="UTF-8"?>
    <configuration>
      <metadata>
        <version>1.0</version>
        <environment>production</environment>
      </metadata>
      <settings category="database">
        <setting key="db.host">localhost</setting>
        <setting key="db.port">5432</setting>
      </settings>
      <settings category="cache">
        <setting key="cache.ttl">3600</setting>
        <setting key="cache.enabled">true</setting>
      </settings>
      <property name="app.name" value="MyApp"/>
      <property name="app.version">2.0.1</property>
    </configuration>"""
    
    service.handleConfigurationRequest(sampleXml) match {
      case Right(config) =>
        println("Configuration parsed successfully:")
        println(s"All settings: ${config.settings}")
        println(s"Categories: ${config.categorizedSettings.keys.mkString(", ")}")
        println(s"Metadata: ${config.metadata}")
      case Left(error) =>
        println(s"Error: $error")
    }
  }
}